(function(){
  var questions = [{"html":"<span class=\"code-comment\"># Create a variable called name</span>","correctCode":"name = \"Ryan\"","optionsRaw":["name = \"Ryan\"","name = Ryan","SET name TO \"Ryan\"","age = 15"],"explanation":"Strings must be wrapped in quotes. Variable assignment uses '='."},{"html":"<span class=\"code-comment\"># Create a variable called age</span>","correctCode":"age = 16","optionsRaw":["age = 16","age : 16","SET age TO 16","name = \"Sam\""],"explanation":"Numbers do not need quotes. Python uses '=' for assignment."},{"html":"<span class=\"code-comment\"># Create a variable called city</span>","correctCode":"city = \"London\"","optionsRaw":["city = \"London\"","city = London","city : \"London\"","SET city TO \"London\""],"explanation":"Strings must be wrapped in quotes."},{"html":"<span class=\"code-comment\"># Create a variable called school</span>","correctCode":"school = \"Hogwarts\"","optionsRaw":["school = \"Hogwarts\"","school = Hogwarts","SET school = \"Hogwarts\"","school == \"Hogwarts\""],"explanation":"Missing quotes causes a NameError."},{"html":"<span class=\"code-comment\"># Create a variable called hobby</span>","correctCode":"hobby = \"Coding\"","optionsRaw":["hobby = \"Coding\"","hobby = Coding","SET hobby TO \"Coding\"","hobby : \"Coding\""],"explanation":"Strings must be wrapped in quotes."},{"html":"<span class=\"code-comment\"># Create a variable called score</span>","correctCode":"score = 100","optionsRaw":["score = 100","score : 100","SET score TO 100","score == 100"],"explanation":"Numbers do not need quotes. Use '=' to assign."},{"html":"<span class=\"code-comment\"># Create a variable called power</span>","correctCode":"power = \"Flying\"","optionsRaw":["power = \"Flying\"","power = Flying","SET power TO \"Flying\"","power = 10"],"explanation":"Strings must be wrapped in quotes."},{"html":"<span class=\"code-comment\"># Create a variable called year</span>","correctCode":"year = 9","optionsRaw":["year = 9","year : 9","SET year TO 9","year == 9"],"explanation":"Numbers do not need quotes."}];
  var idx=0, score=0;
  var prog=document.getElementById('level7-prog');
  var scoreEl=document.getElementById('level7-score');
  var qEl=document.getElementById('level7-q');
  var optsEl=document.getElementById('level7-opts');
  var fb=document.getElementById('level7-fb');
  var exp=document.getElementById('level7-exp');
  function shuffle(a){ return a.slice().sort(function(){return Math.random()-0.5;}); }
  function render(){
    if(idx>=questions.length){ finish(); return; }
    var q=questions[idx];
    prog.textContent='Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent='Score: '+score;
    qEl.innerHTML=q.html;
    optsEl.innerHTML='';
    fb.textContent=''; fb.className='ex-feedback';
    exp.style.display='none'; exp.textContent='';
    shuffle(q.optionsRaw).forEach(function(opt){
      var btn=document.createElement('button');
      btn.className='ex-opt';
      btn.textContent=opt;
      btn.onclick=function(){
        optsEl.querySelectorAll('.ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correctCode) b.classList.add('correct'); });
        exp.textContent=q.explanation || '';
        exp.style.display=q.explanation ? 'block' : 'none';
        if(opt===q.correctCode){
          btn.classList.add('correct'); score++; scoreEl.textContent='Score: '+score;
          fb.className='ex-feedback ok'; fb.textContent='Correct.';
          setTimeout(function(){ idx++; render(); }, 1100);
        } else {
          btn.classList.add('wrong');
          fb.className='ex-feedback err'; fb.textContent='Incorrect. The answer is: '+q.correctCode;
          setTimeout(function(){ idx++; render(); }, 2200);
        }
      };
      optsEl.appendChild(btn);
    });
  }
  function finish(){
    prog.textContent='Complete'; qEl.innerHTML=''; optsEl.innerHTML=''; exp.style.display='none';
    var pass = score >= Math.ceil(questions.length*0.7);
    fb.className='ex-feedback '+(pass?'ok':'hint');
    fb.textContent = 'You scored '+score+' out of '+questions.length+'. '+(pass?'Well done.':'Use the explanations and try again with your teacher if needed.');
    window.__markStepComplete && window.__markStepComplete();
  }
  render();
})();

