(function(){
  var questions = [{"html":"<span class=\"code-comment\"># Create a variable called name</span>","correctCode":"name\\s*=\\s*(?:\"[^\"]*\"|'[^']*')","useRegex":true,"notice":"Strings need quotes! e.g. name = \"Ryan\""},{"html":"<span class=\"code-comment\"># Create a variable called age</span>","correctCode":"age\\s*=\\s*\\d+","useRegex":true,"notice":"Numbers do not use quotes! e.g. age = 15"},{"html":"<span class=\"code-comment\"># Create a variable called city</span>","correctCode":"city\\s*=\\s*(?:\"[^\"]*\"|'[^']*')","useRegex":true,"notice":"Strings need quotes! e.g. city = \"London\""},{"html":"<span class=\"code-comment\"># Create a variable called school</span>","correctCode":"school\\s*=\\s*(?:\"[^\"]*\"|'[^']*')","useRegex":true,"notice":"e.g. school = \"Hogwarts\""},{"html":"<span class=\"code-comment\"># Create a variable called score</span>","correctCode":"score\\s*=\\s*\\d+","useRegex":true,"notice":"e.g. score = 100"},{"html":"<span class=\"code-comment\"># Create a variable called hobby</span>","correctCode":"hobby\\s*=\\s*(?:\"[^\"]*\"|'[^']*')","useRegex":true,"notice":"e.g. hobby = \"Coding\""},{"html":"<span class=\"code-comment\"># Create a variable called year</span>","correctCode":"year\\s*=\\s*\\d+","useRegex":true,"notice":"e.g. year = 9"},{"html":"<span class=\"code-comment\"># Create a variable called power</span>","correctCode":"power\\s*=\\s*(?:\"[^\"]*\"|'[^']*')","useRegex":true,"notice":"e.g. power = \"Flying\""}];
  var idx=0, score=0;
  var prog=document.getElementById('level8-prog');
  var scoreEl=document.getElementById('level8-score');
  var qEl=document.getElementById('level8-q');
  var wrap=document.getElementById('level8-editor-wrap');
  var fb=document.getElementById('level8-fb');
  var exp=document.getElementById('level8-exp');
  function okRegex(pattern, value){ return new RegExp('^'+pattern+'$','i').test(value.trim()); }
  function showHint(q){ exp.textContent=q.notice || q.explanation || ''; exp.style.display=exp.textContent ? 'block' : 'none'; }
  function render(){
    if(idx>=questions.length){ finish(); return; }
    var q=questions[idx];
    prog.textContent='Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent='Score: '+score;
    qEl.innerHTML=q.html;
    fb.textContent=''; fb.className='ex-feedback';
    exp.style.display='none'; exp.textContent='';
    wrap.innerHTML="<input id=\"level8-answer\" class=\"ex-input\" type=\"text\" autocomplete=\"off\" spellcheck=\"false\" placeholder=\"Type your code here\"/><button id=\"level8-check\" class=\"ex-btn\" style=\"margin-top:8px\">Check</button>";
    document.getElementById('level8-check').onclick=function(){ check(q); };
    var input=document.getElementById('level8-answer');
    input.onkeydown=function(e){ if(e.key==='Enter' && true) check(q); };
    input.focus();
  }
  function check(q){
    var input=document.getElementById('level8-answer');
    var val=input.value.trim();
    if(!val){ fb.className='ex-feedback hint'; fb.textContent='Type your answer first.'; showHint(q); return; }
    var pass=false;
    if('single'==='commentVar'){
      var lines=val.split(/\r?\n/).map(function(l){return l.trim();}).filter(Boolean);
      if(lines.length<2){ fb.className='ex-feedback hint'; fb.textContent='Use line 1 for a # comment and line 2 for the variable.'; showHint(q); return; }
      var comment=lines[0], code=lines.slice(1).join(' ');
      var commentOk=comment.charAt(0)==='#' && (q.keywords||[]).every(function(k){ return comment.toLowerCase().indexOf(String(k).toLowerCase())!==-1; });
      pass=commentOk && okRegex(q.correctCode, code);
      if(!commentOk){ fb.className='ex-feedback hint'; fb.textContent='Your comment must start with # and include: '+(q.keywords||[]).join(', '); showHint(q); return; }
    } else {
      pass = q.useRegex ? okRegex(q.correctCode, val) : val===q.correctCode;
    }
    if(pass){
      score++; scoreEl.textContent='Score: '+score; input.classList.add('correct');
      fb.className='ex-feedback ok'; fb.textContent='Correct.';
      setTimeout(function(){ idx++; render(); }, 1000);
    } else {
      input.classList.add('wrong'); fb.className='ex-feedback err'; fb.textContent='Not quite. Check the syntax carefully.'; showHint(q);
    }
  }
  function finish(){
    prog.textContent='Complete'; qEl.innerHTML=''; wrap.innerHTML=''; exp.style.display='none';
    var pass = score >= Math.ceil(questions.length*0.7);
    fb.className='ex-feedback '+(pass?'ok':'hint');
    fb.textContent='You scored '+score+' out of '+questions.length+'. '+(pass?'Good work.':'Review the examples, then try similar questions again.');
    window.__markStepComplete && window.__markStepComplete();
  }
  render();
})();

