(function(){
  var questions = [{"html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">name</span> in a variable and <span class=\"green-keyword\">print</span> it alongside a message.</span>","correctCode":"name\\s*=\\s*(?:\"[^\"]*\"|'[^']*')\\s*[\\r\\n]+\\s*print\\s*\\(\\s*(?:(?:\"[^\"]*\"|'[^']*')\\s*,\\s*name|name\\s*,\\s*(?:\"[^\"]*\"|'[^']*'))\\s*\\)","useRegex":true,"notice":"Syntax:\nvariable = \"value\"\nprint(\"Message\", variable)"},{"html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">age</span> in a variable and <span class=\"green-keyword\">display</span> it with a message.</span>","correctCode":"age\\s*=\\s*\\d+\\s*[\\r\\n]+\\s*print\\s*\\(\\s*(?:(?:\"[^\"]*\"|'[^']*')\\s*,\\s*age|age\\s*,\\s*(?:\"[^\"]*\"|'[^']*'))\\s*\\)","useRegex":true,"notice":"Syntax:\nvariable = number\nprint(\"Message\", variable)"},{"html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">city</span> in a variable and <span class=\"green-keyword\">output</span> it with a message.</span>","correctCode":"city\\s*=\\s*(?:\"[^\"]*\"|'[^']*')\\s*[\\r\\n]+\\s*print\\s*\\(\\s*(?:(?:\"[^\"]*\"|'[^']*')\\s*,\\s*city|city\\s*,\\s*(?:\"[^\"]*\"|'[^']*'))\\s*\\)","useRegex":true,"notice":"Don't forget to separate the message and variable with a comma."},{"html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">score</span> in a variable and <span class=\"green-keyword\">show</span> it alongside a message.</span>","correctCode":"score\\s*=\\s*\\d+\\s*[\\r\\n]+\\s*print\\s*\\(\\s*(?:(?:\"[^\"]*\"|'[^']*')\\s*,\\s*score|score\\s*,\\s*(?:\"[^\"]*\"|'[^']*'))\\s*\\)","useRegex":true,"notice":"Syntax:\nvar = 100\nprint(\"Score:\", var)"},{"html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">hobby</span> in a variable and <span class=\"green-keyword\">print</span> it with a message.</span>","correctCode":"hobby\\s*=\\s*(?:\"[^\"]*\"|'[^']*')\\s*[\\r\\n]+\\s*print\\s*\\(\\s*(?:(?:\"[^\"]*\"|'[^']*')\\s*,\\s*hobby|hobby\\s*,\\s*(?:\"[^\"]*\"|'[^']*'))\\s*\\)","useRegex":true,"notice":"Use a comma inside the print brackets."},{"html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">school</span> in a variable and <span class=\"green-keyword\">write</span> it with a message.</span>","correctCode":"school\\s*=\\s*(?:\"[^\"]*\"|'[^']*')\\s*[\\r\\n]+\\s*print\\s*\\(\\s*(?:(?:\"[^\"]*\"|'[^']*')\\s*,\\s*school|school\\s*,\\s*(?:\"[^\"]*\"|'[^']*'))\\s*\\)","useRegex":true,"notice":"Syntax:\nvariable = \"value\"\nprint(\"Text\", variable)"},{"html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">superpower</span> in a variable and <span class=\"green-keyword\">display</span> it with a message.</span>","correctCode":"superpower\\s*=\\s*(?:\"[^\"]*\"|'[^']*')\\s*[\\r\\n]+\\s*print\\s*\\(\\s*(?:(?:\"[^\"]*\"|'[^']*')\\s*,\\s*superpower|superpower\\s*,\\s*(?:\"[^\"]*\"|'[^']*'))\\s*\\)","useRegex":true,"notice":"Remember the comma!\nprint(\"My power is\", var)"}];
  var idx=0, score=0;
  var prog=document.getElementById('level12-prog');
  var scoreEl=document.getElementById('level12-score');
  var qEl=document.getElementById('level12-q');
  var wrap=document.getElementById('level12-editor-wrap');
  var fb=document.getElementById('level12-fb');
  var exp=document.getElementById('level12-exp');
  function okRegex(pattern, value){ return new RegExp('^'+pattern+'$','i').test(value.trim()); }
  function showHint(q){ exp.textContent=q.notice || q.explanation || ''; exp.style.display=exp.textContent ? 'block' : 'none'; }
  function render(){
    if(idx>=questions.length){ finish(); return; }
    var q=questions[idx];
    prog.textContent='Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent='Score: '+score;
    qEl.innerHTML=q.html;
    fb.textContent=''; fb.className='ex-feedback';
    exp.style.display='none'; exp.textContent='';
    wrap.innerHTML="<textarea id=\"level12-answer\" class=\"ex-textarea\" rows=\"4\" spellcheck=\"false\" placeholder=\"Write your answer here\"></textarea><button id=\"level12-check\" class=\"ex-btn\" style=\"margin-top:8px\">Check</button>";
    document.getElementById('level12-check').onclick=function(){ check(q); };
    var input=document.getElementById('level12-answer');
    input.onkeydown=function(e){ if(e.key==='Enter' && e.ctrlKey) check(q); };
    input.focus();
  }
  function check(q){
    var input=document.getElementById('level12-answer');
    var val=input.value.trim();
    if(!val){ fb.className='ex-feedback hint'; fb.textContent='Type your answer first.'; showHint(q); return; }
    var pass=false;
    if('varMessage'==='commentVar'){
      var lines=val.split(/\r?\n/).map(function(l){return l.trim();}).filter(Boolean);
      if(lines.length<2){ fb.className='ex-feedback hint'; fb.textContent='Use line 1 for a # comment and line 2 for the variable.'; showHint(q); return; }
      var comment=lines[0], code=lines.slice(1).join(' ');
      var commentOk=comment.charAt(0)==='#' && (q.keywords||[]).every(function(k){ return comment.toLowerCase().indexOf(String(k).toLowerCase())!==-1; });
      pass=commentOk && okRegex(q.correctCode, code);
      if(!commentOk){ fb.className='ex-feedback hint'; fb.textContent='Your comment must start with # and include: '+(q.keywords||[]).join(', '); showHint(q); return; }
    } else {
      pass = q.useRegex ? okRegex(q.correctCode, val) : val===q.correctCode;
    }
    if(pass){
      score++; scoreEl.textContent='Score: '+score; input.classList.add('correct');
      fb.className='ex-feedback ok'; fb.textContent='Correct.';
      setTimeout(function(){ idx++; render(); }, 1000);
    } else {
      input.classList.add('wrong'); fb.className='ex-feedback err'; fb.textContent='Not quite. Check the syntax carefully.'; showHint(q);
    }
  }
  function finish(){
    prog.textContent='Complete'; qEl.innerHTML=''; wrap.innerHTML=''; exp.style.display='none';
    var pass = score >= Math.ceil(questions.length*0.7);
    fb.className='ex-feedback '+(pass?'ok':'hint');
    fb.textContent='You scored '+score+' out of '+questions.length+'. '+(pass?'Good work.':'Review the examples, then try similar questions again.');
    window.__markStepComplete && window.__markStepComplete();
  }
  render();
})();

