(function(){
  var examData = [{"type":"mcq","prompt":"Choose the correct code to create a name variable:","codeHtml":"<span class=\"code-comment\"># Create variable name</span>","correct":"name = \"Ryan\"","options":["name = \"Ryan\"","name = Ryan","SET name TO \"Ryan\"","age = 15"],"explanation":"Strings must be wrapped in quotes. Use '=' for assignment."},{"type":"mcq","prompt":"Choose the correct code to create an age variable:","codeHtml":"<span class=\"code-comment\"># Create variable age</span>","correct":"age = 16","options":["age = 16","age : 16","age = \"16\"","SET age = 16"],"explanation":"Integers (numbers) do not need quotes in Python."},{"type":"mcq","prompt":"Which code outputs: \"I live in London\"","codeHtml":"","correct":"city = \"London\"\nprint(\"I live in\", city)","options":["city = \"London\"\nprint(\"I live in\", city)","city = \"London\"\nprint(\"I live in\" city)","city = \"London\"\nprint(\"I live in\" + city)","city = \"London\"\nprint(\"City:\", city)"],"explanation":"To print a string and a variable together using a comma, Python adds a space automatically."},{"type":"text_var","prompt":"Create a variable called <span class=\"green-keyword\">color</span> and store a value in it.","targetVar":"color","isString":true,"explanation":"Format: color = \"Red\""},{"type":"text_var","prompt":"Create a variable called <span class=\"green-keyword\">score</span> and set it to a number.","targetVar":"score","isString":false,"explanation":"Format: score = 100 (No quotes for numbers)"},{"type":"text_var_com","prompt":"Create a variable called <span class=\"green-keyword\">pet</span> with an appropriate # comment containing the word 'variable'.","targetVar":"pet","isString":true,"keywords":["variable","pet"],"explanation":"Format:\n# Create variable pet\npet = \"Dog\""},{"type":"text_var_print","prompt":"Store your <span class=\"green-keyword\">team</span> in a variable and <span class=\"green-keyword\">print</span> it.","targetVar":"team","isString":true,"explanation":"Format:\nteam = \"Lions\"\nprint(team)"},{"type":"text_var_print_multi","prompt":"Store your <span class=\"green-keyword\">level</span> in a variable (number) and print it with a message.","targetVar":"level","isString":false,"explanation":"Format:\nlevel = 5\nprint(\"Level:\", level)"},{"type":"text_var_print_multi","prompt":"Store your <span class=\"green-keyword\">food</span> in a variable and output it with a message.","targetVar":"food","isString":true,"explanation":"Format:\nfood = \"Pizza\"\nprint(\"I like\", food)"},{"type":"extended_var","prompt":"Write a script to store your <b>Name</b>, <b>Age</b>, and <b>Hobby</b> in 3 variables.\nThen print each one alongside an appropriate message (e.g. print(\"Name:\", name)).","explanation":"You need to assign 'name', 'age', and 'hobby', and use print(\"Message\", var) for each one."}];
  var idx=0, score=0;
  var prog=document.getElementById('s2-prog');
  var scoreEl=document.getElementById('s2-score');
  var wrap=document.getElementById('s2-wrap');
  function rx(pattern, value){ return new RegExp(pattern,'im').test(value); }
  function hasAssign(code, name, isString){
    var p = isString ? name+'\\s*=\\s*(?:"[^"]+"|\'[^\']+\')' : name+'\\s*=\\s*\\d+';
    return rx(p, code);
  }
  function hasPrintVar(code, name){ return rx('print\\s*\\([^)]*\\b'+name+'\\b[^)]*\\)', code); }
  function render(){
    if(idx>=examData.length){ finish(); return; }
    var q=examData[idx];
    prog.textContent='Question '+(idx+1)+' of '+examData.length;
    scoreEl.textContent='Score: '+score;
    if(q.type==='mcq'){ renderMcq(q); } else { renderText(q); }
  }
  function renderMcq(q){
    var html='<div class="ex-box"><div class="ex-prompt" style="color:#89b4fa;font-family:sans-serif;font-size:0.85rem;margin-bottom:6px">'+q.prompt+'</div>';
    if(q.codeHtml) html+='<div class="ex-code" style="margin-bottom:10px">'+q.codeHtml+'</div>';
    html+='<div class="ex-options" id="s2-opts"></div><div class="ex-feedback" id="s2-fb"></div><div class="ex-explanation" id="s2-exp" style="display:none"></div></div>';
    wrap.innerHTML=html;
    q.options.slice().sort(function(){return Math.random()-0.5;}).forEach(function(opt){
      var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=opt;
      btn.onclick=function(){
        document.querySelectorAll('#s2-opts .ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct) b.classList.add('correct'); });
        var fb=document.getElementById('s2-fb'), exp=document.getElementById('s2-exp');
        exp.textContent=q.explanation||''; exp.style.display=exp.textContent?'block':'none';
        if(opt===q.correct){ btn.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(function(){idx++;render();},1100); }
        else { btn.classList.add('wrong'); fb.className='ex-feedback err'; fb.textContent='Incorrect. The answer is shown in green.'; setTimeout(function(){idx++;render();},2200); }
      };
      document.getElementById('s2-opts').appendChild(btn);
    });
  }
  function renderText(q){
    var html='<div class="ex-box"><div class="ex-prompt" style="color:#89b4fa;font-family:sans-serif;font-size:0.85rem;margin-bottom:8px">'+q.prompt.replace(/\n/g,'<br>')+'</div>';
    html+='<textarea id="s2-ta" class="ex-textarea" rows="'+(q.type==='extended_var'?10:5)+'" spellcheck="false" placeholder="Write your code here"></textarea>';
    html+='<button id="s2-check" class="ex-btn" style="margin-top:8px">Check</button><div class="ex-feedback" id="s2-fb"></div><div class="ex-explanation" id="s2-exp" style="display:none">'+(q.explanation||'')+'</div></div>';
    wrap.innerHTML=html;
    document.getElementById('s2-check').onclick=function(){ checkText(q); };
    document.getElementById('s2-ta').focus();
  }
  function checkText(q){
    var code=document.getElementById('s2-ta').value.trim();
    var fb=document.getElementById('s2-fb'), exp=document.getElementById('s2-exp');
    exp.style.display='block';
    if(!code){ fb.className='ex-feedback hint'; fb.textContent='Write your answer first.'; return; }
    var ok=false;
    if(q.type==='text_var') ok=hasAssign(code,q.targetVar,q.isString);
    else if(q.type==='text_var_com') ok=hasAssign(code,q.targetVar,q.isString) && /^\s*#/m.test(code) && (q.keywords||[]).every(function(k){return code.toLowerCase().indexOf(String(k).toLowerCase())!==-1;});
    else if(q.type==='text_var_print') ok=hasAssign(code,q.targetVar,q.isString) && hasPrintVar(code,q.targetVar);
    else if(q.type==='text_var_print_multi') ok=hasAssign(code,q.targetVar,q.isString) && hasPrintVar(code,q.targetVar) && /print\s*\([^)]*("[^"]+"|\'[^\']+\')[^)]*,/.test(code);
    else if(q.type==='extended_var') ok=hasAssign(code,'name',true) && hasAssign(code,'age',false) && hasAssign(code,'hobby',true) && hasPrintVar(code,'name') && hasPrintVar(code,'age') && hasPrintVar(code,'hobby');
    if(ok){ score++; scoreEl.textContent='Score: '+score; fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(function(){idx++;render();},1200); }
    else { fb.className='ex-feedback err'; fb.textContent='Not quite. Use the scaffold shown below.'; }
  }
  function finish(){
    var pct=Math.round(score/examData.length*100);
    var grade=pct>=90?'Outstanding':pct>=70?'Secure':pct>=50?'Developing':'Needs more practice';
    wrap.innerHTML='<div class="ex-box"><p style="font-family:sans-serif;font-size:1rem;font-weight:600;color:#cdd6f4;margin-bottom:6px">Stage 2 complete: '+score+'/'+examData.length+' ('+pct+'%)</p><p style="font-family:sans-serif;font-size:0.9rem;color:#a6adc8;margin-bottom:10px">Grade: '+grade+'</p><p style="font-family:sans-serif;font-size:0.85rem;color:#bac2de">You have practised creating variables, choosing strings or numbers, adding comments, and printing variables with messages.</p></div>';
    prog.textContent='Complete'; scoreEl.textContent='';
    window.__markStepComplete && window.__markStepComplete();
  }
  render();
})();

