(function(){
  var mcqPool = [{"prompt":"Choose the correct variable creation:","html":"<span class=\"code-comment\"># Create a variable called name</span>","correct":"name = \"Ryan\"","options":["name = \"Ryan\"","name = Ryan","SET name TO \"Ryan\"","age = 15"]},{"prompt":"Choose the correct variable creation:","html":"<span class=\"code-comment\"># Create a variable called age</span>","correct":"age = 16","options":["age = 16","age : 16","age = \"sixteen\"","SET age TO 16"]},{"prompt":"Which code prints a variable with a message?","html":"<span style=\"font-size:0.9rem\">Output: My score is 100</span>","correct":"score = 100\nprint(\"My score is\", score)","options":["score = 100\nprint(\"My score is\", score)","score = 100\nprint(\"My score is\" score)","score = \"100\"\nprint(score)","print(\"My score is\", points)"]}];
  var textPool = [{"label":"Create the variable:","html":"<span class=\"code-comment\"># Create a variable called city</span>","pattern":"city\\s*=\\s*(?:\"[^\"]+\"|'[^']+')","hint":"Example: city = \"London\"","rows":1},{"label":"Create the variable:","html":"<span class=\"code-comment\"># Create a variable called score</span>","pattern":"score\\s*=\\s*\\d+","hint":"Example: score = 100","rows":1},{"label":"Store and print:","html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">name</span> and print it.</span>","pattern":"name\\s*=\\s*(?:\"[^\"]+\"|'[^']+')\\s*[\\r\\n]+\\s*print\\s*\\(\\s*name\\s*\\)","hint":"name = \"Ryan\"\nprint(name)","rows":3},{"label":"Print with a message:","html":"<span style=\"font-size:0.9rem\">Store your <span class=\"green-keyword\">hobby</span> and print it with a message.</span>","pattern":"hobby\\s*=\\s*(?:\"[^\"]+\"|'[^']+')\\s*[\\r\\n]+\\s*print\\s*\\([^)]*\\bhobby\\b[^)]*\\)","hint":"hobby = \"Coding\"\nprint(\"Hobby:\", hobby)","rows":4}];
  var streak=0, best=parseInt(localStorage.getItem("pylearn_variables_best")||'0',10);
  document.getElementById('var-ep-best').textContent=best;
  function rand(a){ return a[Math.floor(Math.random()*a.length)]; }
  function correct(){ streak++; if(streak>best){ best=streak; localStorage.setItem("pylearn_variables_best", best); document.getElementById('var-ep-best').textContent=best; } document.getElementById('var-ep-streak').textContent=streak; }
  function wrong(){ streak=0; document.getElementById('var-ep-streak').textContent=streak; }
  function next(){ Math.random()<0.5 ? showMcq(rand(mcqPool)) : showText(rand(textPool)); }
  function showMcq(q){
    var wrap=document.getElementById('var-ep-q');
    wrap.innerHTML='<div class="ex-prompt">'+q.prompt+'</div><div class="ex-code" style="margin-bottom:10px">'+q.html+'</div><div class="ex-options" id="var-ep-opts"></div><div class="ex-feedback" id="var-ep-fb"></div>';
    q.options.slice().sort(function(){return Math.random()-0.5;}).forEach(function(o){
      var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=o;
      btn.onclick=function(){
        document.querySelectorAll('#var-ep-opts .ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct)b.classList.add('correct'); });
        var fb=document.getElementById('var-ep-fb');
        if(o===q.correct){ btn.classList.add('correct'); correct(); fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(next,1000); }
        else { btn.classList.add('wrong'); wrong(); fb.className='ex-feedback err'; fb.textContent='Incorrect. The answer is shown in green.'; }
      };
      document.getElementById('var-ep-opts').appendChild(btn);
    });
  }
  function showText(q){
    var wrap=document.getElementById('var-ep-q');
    var field=q.rows>1?'<textarea id="var-ep-answer" class="ex-textarea" rows="'+q.rows+'" spellcheck="false" placeholder="Write your code here"></textarea>':'<input id="var-ep-answer" class="ex-input" type="text" autocomplete="off" spellcheck="false" placeholder="Type your code here"/>';
    wrap.innerHTML='<div class="ex-prompt">'+q.label+'</div><div style="margin-bottom:10px">'+q.html+'</div>'+field+'<button id="var-ep-check" class="ex-btn" style="margin-top:8px">Check</button><div class="ex-feedback" id="var-ep-fb"></div><div class="ex-explanation" id="var-ep-hint" style="display:none"></div>';
    document.getElementById('var-ep-check').onclick=function(){
      var input=document.getElementById('var-ep-answer'); var val=input.value.trim(); var fb=document.getElementById('var-ep-fb'); var hint=document.getElementById('var-ep-hint');
      if(!val){ fb.className='ex-feedback hint'; fb.textContent='Type your answer first.'; hint.textContent=q.hint; hint.style.display='block'; return; }
      if(new RegExp('^'+q.pattern+'$','i').test(val)){ input.classList.add('correct'); correct(); fb.className='ex-feedback ok'; fb.textContent='Correct.'; setTimeout(next,1000); }
      else { input.classList.add('wrong'); wrong(); fb.className='ex-feedback err'; fb.textContent='Not quite. Check the syntax.'; hint.textContent=q.hint; hint.style.display='block'; }
    };
    document.getElementById('var-ep-answer').focus();
  }
  next();
})();
